/**
 * 初始化
 */
function ViewPort(opt){
  root.ajaxGet('/s/sess', function(err, data){
    opt['session'] = JSON.parse(data) || {};
    root.ajaxGet('/r/apps/user/getUserOdpsInfo', function(err, newData){
      var rtn = JSON.parse(newData) || {};
      if(rtn.returnCode == 0){
        opt['session'].user.odpsRealKey = rtn.returnValue.odpsAccessKey;
      }
      context.init(opt);
      var app = App._create(config);
      if(window.history.pushState){
        $(window).bind('popstate',function(e){
          if(e.originalEvent.state){
            app.onRouterChange();
          }
        });
      }else{
        $(window).bind('hashchange',function(e){
          app.onRouterChange();
        });
      }
    });
  });
}
exports = module.exports = ViewPort;